const API_KEY = process.env.SENDGRID_API_KEY;
if (!API_KEY) throw new Error('SENDGRID_API_KEY environment variable is required');
sgMail.setApiKey(API_KEY);

const DEFAULT_FROM = process.env.SENDGRID_FROM_EMAIL || 'noreply@yourdomain.com';

interface SendEmailOptions {
  to: string | string[];
  subject: string;
  html: string;
  text?: string;
  templateId?: string;
  dynamicTemplateData?: Record<string, unknown>;
}

export class EmailService {
  static async send(options: SendEmailOptions): Promise<void> {
    const msg: MailDataRequired = {
      to: options.to,
      from: DEFAULT_FROM,
      subject: options.subject,
      html: options.html,
      ...(options.text && { text: options.text }),
    };

    try {
      await sgMail.send(msg);
    } catch (err: any) {
      const body = err?.response?.body;
      throw new Error(`SendGrid error: ${JSON.stringify(body || err.message)}`);
    }
  }

  static async sendTemplate(
    to: string | string[],
    templateId: string,
    data: Record<string, unknown>,
  ): Promise<void> {
    const msg: MailDataRequired = {
      to,
      from: DEFAULT_FROM,
      templateId,
      dynamicTemplateData: data,
    } as MailDataRequired;

    try {
      await sgMail.send(msg);
    } catch (err: any) {
      const body = err?.response?.body;
      throw new Error(`SendGrid error: ${JSON.stringify(body || err.message)}`);
    }
  }
}
