export class WebSocketService {
  private wss: WebSocketServer;
  private clients: Set<WebSocket> = new Set();
  private messageHistory: Array<{ timestamp: number; data: any }> = [];

  constructor(server: any) {
    this.wss = new WebSocketServer({ server });
    this.wss.on('connection', (socket: WebSocket) => {
      this.clients.add(socket);
      socket.send(JSON.stringify(this.messageHistory.slice(-100)));
      socket.on('message', (raw: Buffer) => {
        const data = JSON.parse(raw.toString());
        this.messageHistory.push({ timestamp: Date.now(), data });
        this.broadcast(data);
      });
    });
    setInterval(() => this.broadcastMetrics(), 5000);
  }

  private broadcast(data: any) {
    for (const client of this.clients) {
      if (client.readyState === WebSocket.OPEN) client.send(JSON.stringify(data));
    }
  }

  private broadcastMetrics() {
    this.broadcast({ type: 'metrics', clients: this.clients.size, messages: this.messageHistory.length });
  }
}"}

