{"content": "import csv
import json
from datetime import datetime

def validate_record(record: dict) -> bool:
    required = ['id', 'timestamp', 'value']
    return all(key in record for key in required)

def parse_timestamp(ts: str) -> datetime:
    return datetime.strptime(ts, '%Y-%m-%d %H:%M:%S')

def process_batch(records: list[dict]) -> list[dict]:
    results = []
    for record in records:
        if not validate_record(record):
            continue
        try:
            record['timestamp'] = parse_timestamp(record['timestamp'])
            record['value'] = float(record['value'])
            transformed = transform_record(record)
            results.append(transformed)
        except (ValueError, KeyError):
            continue
    return results

def transform_record(record: dict) -> dict:
    return {
        'id': record['id'],
        'date': record['timestamp'].strftime('%Y-%m-%d'),
        'hour': record['timestamp'].hour,
        'value': round(record['value'], 2),
        'category': categorize(record['value']),
    }

def categorize(value: float) -> str:
    if value < 0:
        return 'negative'
    elif value < 100:
        return 'low'
    elif value < 1000:
        return 'medium'
    return 'high'

def run_pipeline(input_path: str, output_path: str):
    with open(input_path) as f:
        reader = csv.DictReader(f)
        records = list(reader)

    processed = process_batch(records)

    with open(output_path, 'w') as f:
        json.dump(processed, f, indent=2, default=str)"}

